from crewai.tools import BaseTool

class StrictSearchTool(BaseTool):
    name: str = "StrictSearch"
    description: str = "Search the internal knowledge base for technical documentation."

    def _run(self, query: str) -> str:
        if len(query) < 5:
            raise ValueError(
                f"Query '{query}' is too short. Provide at least 5 characters "
                "with a specific technical term."
            )
        # ... real search ...
        return "Documentation result here"

